// galeria.js — Galería de trabajos por constructor
// Añade funcionalidad al botón "Galería de trabajos" en constructores.html
// NO modifica ningún archivo existente

(function () {

    // ── Clave de almacenamiento ───────────────────────────────────────────────
    const STORAGE_PREFIX = 'mom_galeria_';

    // ── Helpers de persistencia ───────────────────────────────────────────────

    function obtenerGaleria(constructorId) {
        try {
            return JSON.parse(localStorage.getItem(STORAGE_PREFIX + constructorId) || '[]');
        } catch { return []; }
    }

    function guardarGaleria(constructorId, fotos) {
        localStorage.setItem(STORAGE_PREFIX + constructorId, JSON.stringify(fotos));
    }


    // ── Fotos default (seed) por constructor ──────────────────────────────────

    const GALERIA_SEED = {
        2: [ // Daniel Masís Calero
            {
                src: "data:image/jpeg;base64,",
                caption: "Tablero eléctrico",
                fecha: "2026"
            }
        ]
    };

    // Si la galería de un constructor está vacía, carga las fotos seed
    function asegurarSeed(constructorId) {
        const fotos = obtenerGaleria(constructorId);
        if (fotos.length === 0 && GALERIA_SEED[constructorId]) {
            guardarGaleria(constructorId, GALERIA_SEED[constructorId]);
        }
    }

    // ── Sesión: detecta si el usuario logueado ES el constructor de esa tarjeta
    function obtenerSesion() {
        try { return JSON.parse(localStorage.getItem('mom_sesion') || 'null'); } catch { return null; }
    }

    function esConstructorDueno(constructorId) {
        const sesion = obtenerSesion();
        if (!sesion) return false;
        // Compara por userId (tarjeta guardada con persistenciaAPI) o por id numérico
        // que coincida con el constructor del JSON semilla
        const c = (typeof todosLosConstructores !== 'undefined')
            ? todosLosConstructores.find(c => c.id === constructorId)
            : null;
        if (c && c.userId && c.userId === sesion.id) return true;
        // Para constructores semilla: sólo si el rol es constructor Y el nombre coincide
        if (sesion.rol === 'constructor' && c && c.nombre === sesion.nombre) return true;
        return false;
    }

    // ── Crear e inyectar el modal de galería en el DOM ────────────────────────

    function crearModal() {
        if (document.getElementById('galeriaModal')) return; // ya existe

        const overlay = document.createElement('div');
        overlay.id = 'galeriaModal';
        overlay.className = 'modal-overlay';
        overlay.style.zIndex = '2500';
        overlay.innerHTML = `
            <div class="modal-box" style="max-width:680px;width:min(95%,680px);padding:28px 24px;">
                <button class="modal-close" id="galeriaModalClose" aria-label="Cerrar">&times;</button>
                <h3 id="galeriaTitulo" style="font-size:1.25rem;margin-bottom:6px;">Galería de trabajos</h3>
                <p id="galeriaSubtitulo" style="font-size:0.85rem;color:#888;margin-bottom:18px;text-align:center;"></p>

                <!-- Zona de subida (solo visible para el dueño) -->
                <div id="galeriaUploadZona" style="display:none;margin-bottom:20px;">
                    <label id="galeriaUploadLabel"
                        style="display:flex;flex-direction:column;align-items:center;gap:8px;
                               border:2px dashed #c0392b;border-radius:12px;padding:20px;
                               cursor:pointer;background:#fff5f5;transition:background 0.2s;"
                        onmouseenter="this.style.background='#ffe0e0'"
                        onmouseleave="this.style.background='#fff5f5'">
                        <svg viewBox="0 0 24 24" width="32" height="32" fill="none" stroke="#c0392b" stroke-width="1.8">
                            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/>
                            <polyline points="17 8 12 3 7 8"/>
                            <line x1="12" y1="3" x2="12" y2="15"/>
                        </svg>
                        <span style="color:#c0392b;font-weight:600;font-size:0.9rem;">Subir fotos de trabajos</span>
                        <span style="color:#aaa;font-size:0.78rem;">JPG, PNG o WebP · Máx. 5 MB por imagen</span>
                        <input id="galeriaFileInput" type="file" accept="image/*" multiple
                               style="display:none;">
                    </label>
                    <p id="galeriaUploadError" style="color:#c62828;font-size:0.82rem;margin-top:6px;display:none;text-align:center;"></p>
                </div>

                <!-- Grid de fotos -->
                <div id="galeriaGrid" style="
                    display:grid;
                    grid-template-columns:repeat(auto-fill,minmax(140px,1fr));
                    gap:10px;
                    max-height:50vh;
                    overflow-y:auto;
                    padding-right:4px;
                "></div>

                <p id="galeriaVacia"
                   style="text-align:center;color:#aaa;font-size:0.95rem;padding:30px 0;display:none;">
                    Aún no hay fotos en esta galería.
                </p>

                <!-- Lightbox de foto ampliada -->
                <div id="galeriaLightbox" style="
                    display:none;position:fixed;top:0;left:0;width:100%;height:100%;
                    background:rgba(0,0,0,0.88);z-index:3500;
                    justify-content:center;align-items:center;flex-direction:column;gap:16px;">
                    <button id="galeriaLightboxClose" style="
                        position:absolute;top:18px;right:22px;background:none;border:none;
                        color:white;font-size:2.2rem;cursor:pointer;line-height:1;"
                        aria-label="Cerrar">&times;</button>
                    <img id="galeriaLightboxImg" src="" alt="Foto ampliada"
                         style="max-width:90vw;max-height:80vh;border-radius:10px;object-fit:contain;">
                    <p id="galeriaLightboxCaption"
                       style="color:#ddd;font-size:0.88rem;text-align:center;padding:0 20px;max-width:600px;"></p>
                </div>
            </div>
        `;

        document.body.appendChild(overlay);

        // Cerrar modal al hacer clic en el fondo o en la X
        overlay.addEventListener('click', function (e) {
            if (e.target === overlay) cerrarGaleriaModal();
        });
        document.getElementById('galeriaModalClose').addEventListener('click', cerrarGaleriaModal);

        // Lightbox — cerrar
        document.getElementById('galeriaLightboxClose').addEventListener('click', function () {
            document.getElementById('galeriaLightbox').style.display = 'none';
        });
        document.getElementById('galeriaLightbox').addEventListener('click', function (e) {
            if (e.target === this) this.style.display = 'none';
        });

        // Input de archivos
        document.getElementById('galeriaFileInput').addEventListener('change', manejarArchivos);

        // Permite hacer clic en el label para abrir el selector
        document.getElementById('galeriaUploadLabel').addEventListener('click', function (e) {
            if (e.target === this || e.target.closest('label') === this) {
                document.getElementById('galeriaFileInput').click();
            }
        });
    }

    // ── Abrir modal para un constructor específico ────────────────────────────

    let constructorIdActivo = null;
    let constructorNombreActivo = '';

    function abrirGaleriaModal(constructorId, constructorNombre) {
        crearModal();
        constructorIdActivo = constructorId;
        constructorNombreActivo = constructorNombre || 'Constructor';

        document.getElementById('galeriaTitulo').textContent = 'Galería de trabajos';
        document.getElementById('galeriaSubtitulo').textContent = constructorNombreActivo;
        document.getElementById('galeriaUploadError').style.display = 'none';

        // Mostrar zona de subida solo si el usuario es el dueño
        const esDueno = esConstructorDueno(constructorId);
        document.getElementById('galeriaUploadZona').style.display = esDueno ? 'block' : 'none';

        asegurarSeed(constructorId);
        renderizarGaleriaGrid(constructorId);

        const modal = document.getElementById('galeriaModal');
        modal.classList.add('open');
    }

    function cerrarGaleriaModal() {
        const modal = document.getElementById('galeriaModal');
        if (modal) modal.classList.remove('open');
        constructorIdActivo = null;
    }

    // ── Renderizar grilla de fotos ─────────────────────────────────────────────

    function renderizarGaleriaGrid(constructorId) {
        const fotos = obtenerGaleria(constructorId);
        const grid = document.getElementById('galeriaGrid');
        const vacia = document.getElementById('galeriaVacia');
        const esDueno = esConstructorDueno(constructorId);

        grid.innerHTML = '';

        if (fotos.length === 0) {
            vacia.style.display = 'block';
            return;
        }

        vacia.style.display = 'none';

        fotos.forEach((foto, idx) => {
            const wrapper = document.createElement('div');
            wrapper.style.cssText = 'position:relative;border-radius:10px;overflow:hidden;' +
                'box-shadow:0 2px 8px rgba(0,0,0,0.12);background:#eee;';

            const img = document.createElement('img');
            img.src = foto.src;
            img.alt = foto.caption || 'Foto de trabajo';
            img.loading = 'lazy';
            img.style.cssText = 'width:100%;height:110px;object-fit:cover;display:block;cursor:pointer;transition:transform 0.2s;';
            img.addEventListener('mouseenter', () => img.style.transform = 'scale(1.04)');
            img.addEventListener('mouseleave', () => img.style.transform = 'scale(1)');
            img.addEventListener('click', () => abrirLightbox(foto.src, foto.caption));

            wrapper.appendChild(img);

            // Botón eliminar (solo para el dueño)
            if (esDueno) {
                const btnEliminar = document.createElement('button');
                btnEliminar.title = 'Eliminar foto';
                btnEliminar.innerHTML = '&times;';
                btnEliminar.style.cssText = 'position:absolute;top:4px;right:4px;background:rgba(0,0,0,0.55);' +
                    'color:white;border:none;border-radius:50%;width:22px;height:22px;font-size:1rem;' +
                    'cursor:pointer;display:flex;align-items:center;justify-content:center;line-height:1;' +
                    'padding:0;transition:background 0.2s;';
                btnEliminar.addEventListener('mouseenter', () => btnEliminar.style.background = 'rgba(192,57,43,0.85)');
                btnEliminar.addEventListener('mouseleave', () => btnEliminar.style.background = 'rgba(0,0,0,0.55)');
                btnEliminar.addEventListener('click', function (e) {
                    e.stopPropagation();
                    eliminarFoto(constructorId, idx);
                });
                wrapper.appendChild(btnEliminar);
            }

            // Caption
            if (foto.caption) {
                const cap = document.createElement('p');
                cap.textContent = foto.caption;
                cap.style.cssText = 'font-size:0.72rem;color:#555;padding:4px 6px;' +
                    'background:white;margin:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;';
                wrapper.appendChild(cap);
            }

            grid.appendChild(wrapper);
        });
    }

    // ── Lightbox ──────────────────────────────────────────────────────────────

    function abrirLightbox(src, caption) {
        const lb = document.getElementById('galeriaLightbox');
        document.getElementById('galeriaLightboxImg').src = src;
        document.getElementById('galeriaLightboxCaption').textContent = caption || '';
        lb.style.display = 'flex';
    }

    // ── Manejo de archivos subidos ────────────────────────────────────────────

    const MAX_SIZE_MB = 5;

    function manejarArchivos(e) {
        const errorEl = document.getElementById('galeriaUploadError');
        errorEl.style.display = 'none';

        const archivos = Array.from(e.target.files);
        if (!archivos.length) return;

        const errores = [];
        let procesados = 0;

        archivos.forEach(archivo => {
            if (!archivo.type.startsWith('image/')) {
                errores.push(`"${archivo.name}" no es una imagen.`);
                procesados++;
                if (procesados === archivos.length) finalizarSubida(errores);
                return;
            }
            if (archivo.size > MAX_SIZE_MB * 1024 * 1024) {
                errores.push(`"${archivo.name}" supera los ${MAX_SIZE_MB} MB.`);
                procesados++;
                if (procesados === archivos.length) finalizarSubida(errores);
                return;
            }

            const reader = new FileReader();
            reader.onload = function (ev) {
                const fotos = obtenerGaleria(constructorIdActivo);
                fotos.push({
                    src: ev.target.result,
                    caption: archivo.name.replace(/\.[^.]+$/, ''), // nombre sin extensión como caption
                    fecha: new Date().toLocaleDateString('es-CR')
                });
                guardarGaleria(constructorIdActivo, fotos);
                procesados++;
                if (procesados === archivos.length) finalizarSubida(errores);
            };
            reader.onerror = function () {
                errores.push(`Error leyendo "${archivo.name}".`);
                procesados++;
                if (procesados === archivos.length) finalizarSubida(errores);
            };
            reader.readAsDataURL(archivo);
        });

        // Reset del input para poder subir el mismo archivo otra vez
        e.target.value = '';
    }

    function finalizarSubida(errores) {
        renderizarGaleriaGrid(constructorIdActivo);
        if (errores.length) {
            const errorEl = document.getElementById('galeriaUploadError');
            errorEl.textContent = errores.join(' · ');
            errorEl.style.display = 'block';
        }
    }

    // ── Eliminar foto ─────────────────────────────────────────────────────────

    function eliminarFoto(constructorId, idx) {
        if (!confirm('¿Eliminar esta foto?')) return;
        const fotos = obtenerGaleria(constructorId);
        fotos.splice(idx, 1);
        guardarGaleria(constructorId, fotos);
        renderizarGaleriaGrid(constructorId);
    }

    // ── Parchear los botones "Galería de trabajos" ────────────────────────────
    // Se ejecuta después de que constructores.js haya renderizado las tarjetas.
    // Usamos un MutationObserver para detectar cuándo se insertan las tarjetas.

    function parchearBotonesGaleria() {
        document.querySelectorAll('.btn-galeria').forEach(btn => {
            if (btn.dataset.galeriaParchado) return; // evitar duplicados
            btn.dataset.galeriaParchado = '1';

            // Obtener el constructorId desde el enlace "Ver catálogo" del mismo bloque
            const accion = btn.closest('.constructor-accion');
            if (!accion) return;
            const linkCatalogo = accion.querySelector('.btn-ver-catalogo');
            if (!linkCatalogo) return;

            const match = (linkCatalogo.href || '').match(/constructor=(\d+)/);
            if (!match) return;
            const constructorId = parseInt(match[1]);

            // Obtener el nombre del constructor desde la tarjeta
            const card = btn.closest('.constructor-card');
            const nombreEl = card ? card.querySelector('.constructor-info h3') : null;
            const nombre = nombreEl ? nombreEl.textContent.trim() : '';

            // Reemplazar el onclick="return false;" original con la apertura de galería
            btn.removeAttribute('onclick');
            btn.href = '#';
            btn.addEventListener('click', function (e) {
                e.preventDefault();
                abrirGaleriaModal(constructorId, nombre);
            });
        });
    }

    // Observer: detecta cuándo constructores.js inserta las tarjetas
    function observarListaConstructores() {
        const contenedor = document.getElementById('constructoresLista');
        if (!contenedor) return;

        const observer = new MutationObserver(function () {
            parchearBotonesGaleria();
        });

        observer.observe(contenedor, { childList: true, subtree: true });

        // Intento inicial por si ya están renderizadas
        parchearBotonesGaleria();
    }

    document.addEventListener('DOMContentLoaded', function () {
        crearModal();
        observarListaConstructores();
    });

    // Exponer para uso externo si fuera necesario
    window.abrirGaleriaModal = abrirGaleriaModal;

})();